parameters.jsCode:
// Format the AI-generated descriptions into a clean structure
const items = $input.all();
const formData = $('Product Details Form').first().json;
const englishRaw = $('Generate Description').first().json.text || '';
const translationRaw = items[0].json.text || '';

let english = {};
let translations = {};

try {
  const enMatch = englishRaw.match(/\{[\s\S]*\}/);
  if (enMatch) english = JSON.parse(enMatch[0]);
} catch (e) {
  english = { title: formData['Product Name'], fullDescription: englishRaw };
}

try {
  const trMatch = translationRaw.match(/\{[\s\S]*\}/);
  if (trMatch) translations = JSON.parse(trMatch[0]);
} catch (e) {
  translations = {};
}

const output = {
  productName: formData['Product Name'],
  targetAudience: formData['Target Audience'],
  tone: formData['Tone'] || 'Professional',
  deliveryEmail: formData['Delivery Email'],
  english,
  translations,
  generatedAt: new Date().toISOString()
};

return [{ json: output }];

